INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_002_001", "vo_minigame_1013_icon_2_002_001", 2, "訓練はまだ\nここからですわ", 2, 1, 3000, 1000, 2, "調子が上がって\nきたなっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_003_001", "vo_minigame_1013_icon_2_003_001", 2, "クスクス、悪くない\n流れですわね", 2, 2, 3000, 5000, 2, "ほらほら、\nまだいけるだろ？");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_004_001", "vo_minigame_1013_icon_2_004_001", 2, "すばらしい\n記録ですわ", 2, 3, 3000, 10000, 3, "へへっ、おまえら\nやるじゃねえか！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_005_001", "vo_minigame_1013_icon_2_005_001", 2, "乗りに乗って\nいますわね", 3, 4, 3000, 10000, 3, "あたしたちはまだ\n止まらねえぜ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_005_002", "vo_minigame_1013_icon_2_005_002", 2, "まだまだ行きます\nついてきなさい", 3, 5, 3000, 10000, 3, "見てろよ！\nマコト班の快進撃だ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_005_003", "vo_minigame_1013_icon_2_005_003", 2, "エリコ班の\n本領発揮ですわ！", 3, 6, 3000, 10000, 3, "うおぉぉっ！\n絶好調だぜ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_006_001", "vo_minigame_1013_icon_2_006_001", 2, "ここからは\n前人未到の領域です！", 4, 7, 3000, 0, 3, "どこまで行けるか\n楽しみだなっ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_007_001", "vo_minigame_1013_icon_2_007_001", 3, "厄介でしたわ…", 5, 8, 1000, 1, 4, "まだ諦めんなよっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_007_002", "vo_minigame_1013_icon_2_007_002", 3, "油断大敵です", 5, 9, 1000, 1, 4, "冷やっとしたぜ…！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_007_003", "vo_minigame_1013_icon_2_007_003", 3, "忌々しいっ…", 5, 10, 1000, 1, 4, "弱音を吐くなっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_008_001", "vo_minigame_1013_icon_2_008_001", 4, "大所帯ですわね", 6, 11, 1500, 99, 3, "マコト班集合！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_008_002", "vo_minigame_1013_icon_2_008_002", 4, "エリコ班へようこそ", 6, 12, 1500, 99, 3, "連携してくぞ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_020_001", "vo_minigame_1013_icon_2_020_001", 1, "ナナカちゃんに\nお任せあれ", 8, 13, 3000, 0, 6, "みんなに力を！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_022_001", "vo_minigame_1013_icon_2_022_001", 1, "はっはっは！\n任せろ！", 9, 14, 3000, 0, 7, "任せてくれたまえ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_1_023_001", "vo_minigame_1013_icon_2_023_001", 1, "どんどんいくわよ", 10, 15, 3000, 0, 8, "ほな、いきまひょか");
